                                                                                                                                                                                                                        if (field.type === "select" && field.options) return <select className={base} required={field.required} value={formData[field.name] || ""} onChange={(e) => setFormData({ ...formData, [field.name]: e.target.value })}><option value="">Select...</option>{field.options.map((opt) => <option key={opt} value={opt}>{opt}</option>)}</select>;
                                                                                                                                                                                                                            return <input type={field.type === "number" ? "number" : "text"} className={base} placeholder={field.placeholder} required={field.required} value={formData[field.name] || ""} onChange={(e) => setFormData({ ...formData, [field.name]: e.target.value })} />;
